#!/usr/bin/env python3
"""Generate the active W3.5 adjudication and discovery task queue."""
from __future__ import annotations
from pathlib import Path
from report_link_utils import markdown_link
ROOT=Path(__file__).resolve().parents[1]; OUT=ROOT/'docs/planning/next-actions.md'; STATUS=ROOT/'docs/reports/project-status-generated.md'; GAP=ROOT/'docs/reports/research-gap-report.md'
TASKS=[
{"id":"STRATEGIC-001","priority":"high","title":"Freeze the concrete reasoning and contrast corpora","why":"RCS-001 freezes admission rules only. W3.5 cannot execute until nonempty positive and contrast instances, exclusions, source contracts, and observation boundaries are registered prospectively.","affected":["docs/research/reasoning-and-contrast-scope-v1.0.md","theory/evaluation/reasoning-and-contrast-scope-v1.0.json","docs/research/w3-5-specificity-and-discovery-gate-v1.0.md"],"outcome":"An immutable nonempty candidate-independent corpus with explicit admission and exclusion decisions.","risk":"high","branch":"research/freeze-w3-5-corpora","pr":"Freeze W3.5 reasoning and contrast corpora"},
{"id":"STRATEGIC-002","priority":"high","title":"Execute dimensioned GREL-FARA factorization","why":"W0-W4 establish a bounded FARA representation package but do not determine whether its expressive power, translations, constraints, semantics, costs, or reasoning specificity differ from GREL-001.","affected":["docs/research/generic-relational-baseline-v1.0.md","theory/evaluation/generic-relational-baseline-v1.0.json","theory/evaluation/w3-5-specificity-and-discovery-gate.json"],"outcome":"Fixed translation witnesses or explicit failed-translation records and terminal results for all six registered factorization dimensions.","risk":"high","branch":"research/execute-w3-5-factorization","pr":"Execute W3.5 GREL-FARA factorization"},
{"id":"STRATEGIC-003","priority":"high","title":"Execute contrast candidate ablation and reconstruction","why":"Universal candidates must be tested across the frozen corpus and alternative reconstructions rather than inferred from FARA recurrence.","affected":["theory/evaluation/universal-structure-candidate-registry.json","theory/evaluation/reasoning-and-contrast-scope-v1.0.json","docs/research/universal-structure-discovery-target-v1.0.md"],"outcome":"Per-candidate discrimination, ablation, reconstruction, equivalent-reintroduction, and preserved-counterexample records.","risk":"high","branch":"research/execute-w3-5-candidate-tests","pr":"Execute W3.5 candidate ablation and reconstruction"},
{"id":"STRATEGIC-004","priority":"high","title":"Complete W3.5 machinery cost and claim-impact audit","why":"W3.5 cannot authorize W5 without complete cost accounting, immutable evidence digests, preserved failures, and track-specific claim effects.","affected":["docs/research/w3-5-specificity-and-discovery-gate-v1.0.md","theory/evaluation/w3-5-specificity-and-discovery-gate.json","theory/evaluation/central-claim-registry.json","theory/evaluation/research-gates.json"],"outcome":"A terminal W3.5 package satisfying every evidence-backed authorization requirement or an explicit unresolved result.","risk":"high","branch":"research/close-w3-5-adjudication","pr":"Close W3.5 adjudication and claim-impact audit"},
{"id":"STRATEGIC-005","priority":"blocked","title":"Assemble the finite-core theorem or strongest obstruction","why":"ASM-SC-001 through ASM-SC-003 remain open. OBS-SC-010 is resolved, but W5 remains blocked until W3.5 has complete immutable evidence.","affected":["docs/research/s-core-construction-obstruction-ledger-v1.0.md","theory/evaluation/s-core-construction-obstruction-ledger.json","theory/evaluation/thm-target-001.json","theory/evaluation/central-claim-registry.json"],"outcome":"A bounded REP theorem, equivalence, countermodel, proper-subclass result, impossibility result, or explicit unresolved result with dimensioned specificity classification.","risk":"high","branch":"research/assemble-s-core-result","pr":"Assemble S_core theorem or obstruction"}]
def nav_links(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(STATUS,OUT)}",f"- Research Gaps: {markdown_link(GAP,OUT)}",f"- Next Actions: {markdown_link(OUT,OUT)}"]
def main()->int:
    ids=[x['id'] for x in TASKS]; assert len(ids)==len(set(ids))
    lines=['# Next Actions','','## Navigation','',*nav_links(),'','Generated by `python tools/generate_next_tasks.py` under the separated REP, ADJ, and USD program.','','W0-W4 are complete bounded REP packages. The RCS-001 admission framework is frozen, but its concrete corpus is not. W3.5 is the sole live blocker before W5. Representation progress does not update the universal-structure claim.','','## Ranked Next Actions','']
    for task in TASKS:
        affected=[markdown_link(ROOT/path,OUT) for path in task['affected']]
        lines += [f"### {task['id']}: {task['title']}",'','- Source: central research program',f"- Priority: {task['priority']}",f"- Why it matters: {task['why']}",'- Affected files:',*[f'  - {item}' for item in affected],f"- Expected outcome: {task['outcome']}",f"- Risk level: {task['risk']}",f"- Suggested branch name: `{task['branch']}`",f"- Suggested PR title: `{task['pr']}`",'']
    lines += ['## Maintainer Task Briefs','']
    for task in TASKS:
        lines += [f"### Task brief for {task['id']}",'','```markdown',f"Create branch `{task['branch']}`.",f"Scope: {task['title']}.",'Preserve THM-TARGET-001, THM-US-TARGET-001, FAITHFUL-REP-001, P8-ROLE-001, W0-W4, all failures, and every nonclaim.','Do not promote REP progress into USD, necessity, minimality, or uniqueness.','Do not treat the RCS-001 framework as a frozen concrete corpus.','Do not begin W5 while W3.5-SDG-001 remains unresolved or lacks linked immutable evidence.','Validation commands:','- `make research-check`','- `make health-fast`',f"PR title: `{task['pr']}`",'```','']
    lines += ['## Navigation','',*nav_links()]
    OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(f"{OUT.relative_to(ROOT)} tasks={len(TASKS)}"); return 0
if __name__=='__main__': raise SystemExit(main())
